import Foundation

enum NetworkError: Error {
    case invalidURL
    case invalidResponse
    case httpError(Int)
    case decodingError
    case encodingError
    case noData
    case unauthorized
    case serverError
    case unknown
}

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://dev-api.example.com"
        case .staging:
            return "https://staging-api.example.com"
        case .production:
            return "https://api.example.com"
        }
    }
}

struct User: Codable {
    let id: Int
    let email: String
    let name: String
}

struct AuthRequest: Codable {
    let email: String
    let password: String
}

struct AuthResponse: Codable {
    let token: String
    let user: User
}

class NetworkManager {
    static let shared = NetworkManager()
    
    private var environment: Environment = .production
    private var authToken: String?
    
    private init() {}
    
    func setEnvironment(_ environment: Environment) {
        self.environment = environment
    }
    
    func setAuthToken(_ token: String?) {
        self.authToken = token
    }
    
    func login(email: String, password: String, completion: @escaping (Result<AuthResponse, NetworkError>) -> Void) {
        let authRequest = AuthRequest(email: email, password: password)
        
        post(endpoint: "/auth/login", body: authRequest) { (result: Result<AuthResponse, NetworkError>) in
            switch result {
            case .success(let response):
                self.authToken = response.token
                completion(.success(response))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func getUser(userId: Int, completion: @escaping (Result<User, NetworkError>) -> Void) {
        get(endpoint: "/users/\(userId)", completion: completion)
    }
    
    func getUserProfile(completion: @escaping (Result<User, NetworkError>) -> Void) {
        get(endpoint: "/users/me", completion: completion)
    }
    
    private func get<T: Decodable>(endpoint: String, completion: @escaping (Result<T, NetworkError>) -> Void) {
        guard let url = URL(string: environment.baseURL + endpoint) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        executeRequest(request: request, completion: completion)
    }
    
    private func post<T: Encodable, U: Decodable>(endpoint: String, body: T, completion: @escaping (Result<U, NetworkError>) -> Void) {
        guard let url = URL(string: environment.baseURL + endpoint) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        do {
            let encoder = JSONEncoder()
            request.httpBody = try encoder.encode(body)
        } catch {
            completion(.failure(.encodingError))
            return
        }
        
        executeRequest(request: request, completion: completion)
    }
    
    private func executeRequest<T: Decodable>(request: URLRequest, completion: @escaping (Result<T, NetworkError>) -> Void) {
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if error != nil {
                completion(.failure(.unknown))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.invalidResponse))
                return
            }
            
            switch httpResponse.statusCode {
            case 200...299:
                guard let data = data else {
                    completion(.failure(.noData))
                    return
                }
                
                do {
                    let decoder = JSONDecoder()
                    let decodedData = try decoder.decode(T.self, from: data)
                    completion(.success(decodedData))
                } catch {
                    completion(.failure(.decodingError))
                }
                
            case 401:
                completion(.failure(.unauthorized))
                
            case 500...599:
                completion(.failure(.serverError))
                
            default:
                completion(.failure(.httpError(httpResponse.statusCode)))
            }
        }
        
        task.resume()
    }
}